code = '01845') value from dual
/* CHRYS 3/3/2023 TO 01846 EINAI ALLO PRAGMA union all select 8 ord, 'ΗΛΙΚΙΑ ΚΑΤΑ ΤΗΝ ΑΙΤΗΣΗ' code, (select a.value from pen_dec_fact_types_instance a where a.di_document_type_dec_coce_sr = '1' and a.status = '1' and a.ins_insured_id = :p_insured_id and a.di_dec_incr_seq_no_sr = :p_dec_incr_sec_no_sr and a.di_decision_year_sr = :p_dt_decision_year and a.di_dec_unit_code_sr = :p_dt_dec_unit_code and a.title_code = '01865' and a.dec_fact_type_code = '01846') value from dual END CHRYS 3/3/2023 */ union all select 9 ord, 'ΑΣΦΑΛΙΣΗ ΣΤΗΝ ΕΕ./Δ.Ο. ΑΠΟ' code, (select a.value from pen_dec_fact_types_instance a where a.di_document_type_dec_coce_sr = '1' and a.status = '1' and a.ins_insured_id = :p_insured_id and a.di_dec_incr_seq_no_sr = :p_dec_incr_sec_no_sr and a.di_decision_year_sr = :p_dt_decision_year and a.di_dec_unit_code_sr = :p_dt_dec_unit_code and a.title_code = '01865' and a.dec_fact_type_code = '01867') value from dual union all select 10 ord, 'ΑΣΦΑΛΙΣΗ ΣΤΗΝ ΕΕ./Δ.Ο. ΕΩΣ' code, (select a.value from pen_dec_fact_types_instance a where a.di_document_type_dec_coce_sr = '1' and a.status = '1' and a.ins_insured_id = :p_insured_id and a.di_dec_incr_seq_no_sr = :p_dec_incr_sec_no_sr and a.di_decision_year_sr = :p_dt_decision_year and a.di_dec_unit_code_sr = :p_dt_dec_unit_code and a.title_code = '01865' and a.dec_fact_type_code = '01868') value from dual union all select 11 ord, 'ΠΛΑΣΜΑΤΙΚΟ ΕΤΟΣ ΣΥΝΤΑΞΙΟΔΟΤΗΣΗΣ' code, (select a.value from pen_dec_fact_types_instance a where a.di_document_type_dec_coce_sr = '1' and a.status = '1' and a.ins_insured_id = :p_insured_id and a.di_dec_incr_seq_no_sr = :p_dec_incr_sec_no_sr and a.di_decision_year_sr = :p_dt_decision_year and a.di_dec_unit_code_sr = :p_dt_dec_unit_code and a.title_code = '01865' and a.dec_fact_type_code = '01840' ) value from dual union all select 12 ord, 'ΠΡΟΒΛΕΠΟΜΕΝΗ ΗΛΙΚΙΑ ΣΥΝΤΑΞΙΟΔΟΤΗΣΗΣ' code, (select a.value from pen_dec_fact_types_instance a where a.di_document_type_dec_coce_sr = '1' and a.status = '1' and a.ins_insured_id = :p_insured_id and a.di_dec_incr_seq_no_sr = :p_dec_incr_sec_no_sr and a.di_decision_year_sr = :p_dt_decision_year and a.di_dec_unit_code_sr = :p_dt_dec_unit_code and a.title_code = '01865' and a.dec_fact_type_code = '01841') value from dual /* υπολογιζεται οποτε δεν ειναι ειδικη πληροφορια (select a.value from pen_dec_fact_types_instance a where a.di_document_type_dec_coce_sr = '1' and a.status = '1' and a.ins_insured_id = :p_insured_id and a.di_dec_incr_seq_no_sr = :p_dec_incr_sec_no_sr and a.di_decision_year_sr = :p_dt_decision_year and a.di_dec_unit_code_sr = :p_dt_dec_unit_code and a.title_code = '01865' and a.dec_fact_type_code = '01837') value*/ union all select 13 ord, 'ΗΛΙΚΙΑ ΚΑΤΑ ΤΗΝ ΑΙΤΗΣΗ' code, to_char(APPLICATION_AGE) value from PEN_ACC_ANALOGIST_ISODYNAMO where ACCOUNT_NO = :P_ACC_ACCOUNT_NO union all select 14 ord, 'ΠΡΟΒΛΕΠΟΜΕΝΗ ΕΤΟΣ ΣΥΝΤΑΞΙΟΔΟΤΗΣΗΣ' code, to_char( (select a.value from pen_dec_fact_types_instance a where a.di_document_type_dec_coce_sr = '1' and a.status = '1' and a.ins_insured_id = :p_insured_id and a.di_dec_incr_seq_no_sr = :p_dec_incr_sec_no_sr and a.di_decision_year_sr = :p_dt_decision_year and a.di_dec_unit_code_sr = :p_dt_dec_unit_code and a.title_code = '01865' and a.dec_fact_type_code = '01841') + (select to_char(a.date_of_birth,'yyyy') from reg_insured a where a.insured_id = :p_insured_id )) value from dual union all select 15 ord, 'ΣΥΝΤΑΞΙΜΟΣ ΜΙΣΘΟΣ ΣΤΗΝ Ε.Ε./Δ.Ο' code, (select a.value from pen_dec_fact_types_instance a where a.di_document_type_dec_coce_sr = '1' and a.status = '1' and a.ins_insured_id = :p_insured_id and a.di_dec_incr_seq_no_sr = :p_dec_incr_sec_no_sr and a.di_decision_year_sr = :p_dt_decision_year and a.di_dec_unit_code_sr = :p_dt_dec_unit_code and a.title_code = '01865' and a.dec_fact_type_code = '01862') value from dual union all select 16 ord, 'ΣΥΝΤΑΞΙΜΟΣ ΜΙΣΘΟΣ ΥΠΑΛΛΗΛΟΥ ΕΛΛΗΝΙΚΟΥ ΔΗΜΟΣΙΟΥ' code, (select a.value from pen_dec_fact_types_instance a where a.di_document_type_dec_coce_sr = '1' and a.status = '1' and a.ins_insured_id = :p_insured_id and a.di_dec_incr_seq_no_sr = :p_dec_incr_sec_no_sr and a.di_decision_year_sr = :p_dt_decision_year and a.di_dec_unit_code_sr = :p_dt_dec_unit_code and a.title_code = '01865' and a.dec_fact_type_code = '01871') value from dual order by 1 ;

