      function M_49FormatTrigger return boolean is

CURSOR CUR_2019 IS
SELECT AFTER_01_01_2019_FLG, AFTER_01_10_2019_FLG 
FROM PEN_INTRODUCTIONS
WHERE INTRODUCTION_CODE = :CF_35;

V_01_01_2019    PEN_INTRODUCTIONS.AFTER_01_01_2019_FLG%TYPE;
V_01_10_2019    PEN_INTRODUCTIONS.AFTER_01_10_2019_FLG%TYPE;


-- CHRYS 3/6/2021
CURSOR CUR_PERD2 IS
SELECT	AMOUNT
FROM 		PEN_QT_PER_BE_CC_PER_ACCOUNT
WHERE   ACC_ACCOUNT_NO = :P_ACC_ACCOUNT_NO
AND     CP_CALCULATION_PARAMETER_CODE = 'PERD2'
AND     CC_PER_BE_TYPE_PER_DECINS_UPD = '1';   

V_AMOUNT_PERD2		NUMBER;
--END CHRYS 3/6/2021

begin
  -- ΓΙΑ ΥΠΑΓΩΓΕΣ ΠΟΥ ΕΙΝΑΙ ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/1/2019 - Η ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/10/2019
  V_01_01_2019 := '0';
  V_01_10_2019 := '0';
  
  OPEN CUR_2019;
  FETCH CUR_2019 INTO V_01_01_2019,V_01_10_2019;
	CLOSE CUR_2019;
	  
	-- CHRYS 3/6/2021
	OPEN 	CUR_PERD2;
	FETCH	CUR_PERD2
	INTO 	V_AMOUNT_PERD2;
	CLOSE	CUR_PERD2;
	
	-- END CHRYS 3/6/2021
 
 /* CHRYS 3/6/2021  
  IF NVL(V_01_01_2019,'0') = '1' OR NVL(V_01_10_2019,'0') = '1'
  	 then
  	return (FALSE);
  ELSE
  	return (TRUE);
  END IF;
END CHRYS 3/6/2021 */

-- CHRYS 3/6/2021
  IF NVL(V_01_01_2019,'0') = '1' 
  	 then
  	return (FALSE);
  END IF;
  
  IF NVL(V_01_10_2019,'0') = '1' AND V_AMOUNT_PERD2 IS NOT NULL THEN 
  	return (TRUE);
  END IF;
  
  IF NVL(V_01_10_2019,'0') = '1' AND V_AMOUNT_PERD2 IS NULL THEN 
  	return (FALSE);
  END IF;

-- END CHRYS 3/6/2021
  return (TRUE);
end;

      function M_51FormatTrigger return boolean is
/* CHRYS 9/6/2021 
CURSOR CUR_2019 IS
SELECT AFTER_01_01_2019_FLG FROM PEN_INTRODUCTIONS
WHERE INTRODUCTION_CODE = :CF_35;

V_2019    PEN_INTRODUCTIONS.AFTER_01_01_2019_FLG%TYPE;


begin
  -- ΓΙΑ ΥΠΑΓΩΓΕΣ ΠΟΥ ΕΙΝΑΙ ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/1/2019
  V_2019 := '0';
  
  OPEN CUR_2019;
  FETCH CUR_2019
  INTO V_2019;
	CLOSE CUR_2019;

  if :cf_35 in ('00010','00011')
  then
     return (FALSE);
  end if;

  IF V_2019 = '1' THEN
  	return (FALSE);
  ELSE
  	return (TRUE);
  END IF;

  return (TRUE);

end;


END CHRYS 9/6/2021 */
CURSOR CUR_2019 IS
SELECT AFTER_01_01_2019_FLG, AFTER_01_10_2019_FLG 
FROM PEN_INTRODUCTIONS
WHERE INTRODUCTION_CODE = :CF_35;

V_01_01_2019    PEN_INTRODUCTIONS.AFTER_01_01_2019_FLG%TYPE;
V_01_10_2019    PEN_INTRODUCTIONS.AFTER_01_10_2019_FLG%TYPE;


begin
  -- ΓΙΑ ΥΠΑΓΩΓΕΣ ΠΟΥ ΕΙΝΑΙ ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/1/2019 - Η ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/10/2019
  V_01_01_2019 := '0';
  V_01_10_2019 := '0';
  
  OPEN CUR_2019;
  FETCH CUR_2019 INTO V_01_01_2019,V_01_10_2019;
	CLOSE CUR_2019;
	  
  IF NVL(V_01_01_2019,'0') = '1' OR 
  	( NVL(V_01_10_2019,'0') = '1' 
  	AND :cp_award_flag != '8') -- CHRYS 9/6/2021
  	--OR (:CF_35='00008' AND :P_FACTITIOUS_DATE >= TO_DATE('01/01/2019','DD/MM/YYYY'))
  	THEN
  	return (FALSE);
  ELSE
  	return (TRUE);
  END IF;

  return (TRUE);

END ;

