      function CF_FINAL_ANALOG_ISODYN_ETHSIOF return Number is

CURSOR C1 IS
SELECT --ROUND (FINAL_NAT_PENSION_AMT * 0.06 * 12,2 )
				ROUND (FINAL_NAT_PENSION_AMT, 2 )    
FROM   PEN_CALC_NATIONAL_RESULTS  A
WHERE  A.ACCOUNT_NO = :P_ACC_ACCOUNT_NO
;

V_C1 NUMBER;

CURSOR C2 IS
SELECT --ROUND (AVERAGE_INCOME * 0.77 * 12 /100 ,2 )
			ROUND (ADAPODOTIKH_AMT,2 )    
FROM   PEN_CALC_ADAPOD_RESULTS  A
WHERE  A.ACCOUNT_NO = :P_ACC_ACCOUNT_NO
;

V_C2 NUMBER;

L_RET NUMBER;

begin
	OPEN C1;
	FETCH C1
	INTO V_C1;
	CLOSE C1;
	
	OPEN C2;
	FETCH C2
	INTO V_C2;
	CLOSE C2;
	
	RETURN ROUND(V_C1 * :V_SAI0 + V_C2 * :V_SAI1,2);
	EXCEPTION WHEN OTHERS THEN RETURN 0;
  
end;

